class Student:
    def __init__(self, name, scores):
        self.name = name
        self.scores = scores

    def average_score(self):
        return sum(self.scores) / len(self.scores)

    def __str__(self):
        return f"{self.name}: {self.scores} (平均分{self.average_score():.2f})"
